public void init(JSSourceFile[] externs, JSModule[] modules,
    CompilerOptions options) {
  initOptions(options);

  checkFirstModule(modules);

  this.externs = makeCompilerInput(externs, true);
  this.modules = modules;
  // Generate the module graph, and report any errors in the module
  // specification as errors.
  try {
    this.moduleGraph = new JSModuleGraph(modules);
  } catch (JSModuleGraph.ModuleDependenceException e) {
    // problems with the module format.  Report as an error.  The
    // message gives all details.
    report(JSError.make(MODULE_DEPENDENCY_ERROR,
        e.getModule().getName(), e.getDependentModule().getName()));
    return;
  }
  this.inputs = getAllInputsFromModules();
  initBasedOnOptions();

  initInputsByNameMap();
}

private void checkFirstModule(JSModule[] modules) {
  if (modules.length == 0) {
    report(JSError.make(EMPTY_MODULE_LIST_ERROR));
  } else if (modules[0].getInputs().isEmpty()) {
    report(JSError.make(EMPTY_ROOT_MODULE_ERROR,
        modules[0].getName()));
  }
}

Node getNodeForCodeInsertion(JSModule module) {
  if (module == null) {
    if (inputs.length == 0) {
      throw new IllegalStateException("No inputs");
    }

    return inputs[0].getAstRoot(this);
  }

  JSModuleGraph graph = getModuleGraph();
  if (graph == null) {
    throw new IllegalStateException("Compiler not initialized with module graph");
  }

  List<CompilerInput> inputs = module.getInputs();
  if (inputs.size() > 0) {
    return inputs.get(0).getAstRoot(this);
  }
  for (JSModule m : graph.getTransitiveDepsDeepestFirst(module)) {
    inputs = m.getInputs();
    if (inputs.size() > 0) {
      return inputs.get(0).getAstRoot(this);
    }
  }
  throw new IllegalStateException("Module has no inputs");
}
